{"cmd":"set -euo pipefail

# SSHD password auth configuration
mkdir -p /etc/ssh/sshd_config.d
cat > /etc/ssh/sshd_config.d/99-git-password.conf <<'EOF'
PasswordAuthentication yes
PubkeyAuthentication yes
KbdInteractiveAuthentication no
UsePAM yes
EOF

# Ensure privilege separation directory exists and start/restart sshd
mkdir -p /run/sshd
if pgrep -x sshd >/dev/null 2>&1; then
  pkill -HUP sshd
else
  /usr/sbin/sshd
fi

# TLS cert for localhost
mkdir -p /etc/nginx/ssl
if [ ! -f /etc/nginx/ssl/localhost.key ] || [ ! -f /etc/nginx/ssl/localhost.crt ]; then
  openssl req -x509 -nodes -newkey rsa:2048 -days 3650 \
    -keyout /etc/nginx/ssl/localhost.key \
    -out /etc/nginx/ssl/localhost.crt \
    -subj '/CN=localhost'
fi
chmod 600 /etc/nginx/ssl/localhost.key
chmod 644 /etc/nginx/ssl/localhost.crt

# Nginx deployment server config
cat > /etc/nginx/conf.d/git-deploy.conf <<'EOF'
server {
    listen 8443 ssl;
    listen [::]:8443 ssl;
    server_name localhost;

    ssl_certificate     /etc/nginx/ssl/localhost.crt;
    ssl_certificate_key /etc/nginx/ssl/localhost.key;

    root /var/www/git-deploy/main;
    index index.html;

    location / {
        try_files $uri =404;
    }

    location /dev/ {
        alias /var/www/git-deploy/dev/;
        try_files $uri =404;
    }
}
EOF

nginx -t
if pgrep -x nginx >/dev/null 2>&1; then
  nginx -s reload
else
  nginx
fi
","max_output_tokens":5000}

